const items = $input.all();
const results = [];

for (const item of items) {
  const raw = item.json;
  const input = raw.body || raw;

  const imageUrl = input.imageUrl || input.image_url || null;
  const imageBase64 = input.image_base64 || null;

  if (!imageUrl && !imageBase64) {
    throw new Error('An image is required. Send image_url or image_base64. Keys received: ' + Object.keys(input).join(', '));
  }

  const marker =
    input.issue_id ||
    input.issueId ||
    input.id ||
    input.analysis_id ||
    input.analysisId ||
    input.storage_id ||
    input.storageId ||
    input.last_update?.issue_id ||
    input.lastUpdate?.issueId ||
    input.existing_issue?.issue_id ||
    input.existingIssue?.id ||
    null;

  if (!marker) {
    throw new Error('Missing issue marker. Provide issue_id / issueId / id from the user-created record.');
  }

  const issueId = String(marker);

  let lat = 0;
  let lon = 0;
  let addr = 'Unknown';
  if (input.location) {
    lat = parseFloat(input.location.latitude) || 0;
    lon = parseFloat(input.location.longitude) || 0;
    addr = input.location.address || 'Unknown';
  }
  if (lat === 0 && lon === 0) {
    lat = parseFloat(input.latitude) || 0;
    lon = parseFloat(input.longitude) || 0;
  }

  const callbackUrl = input.callback_url || input.callbackUrl || null;

  results.push({
    json: {
      analysis_id: issueId,
      issue_id: issueId,
      marker_id: issueId,
      storage_id: input.storageId || input.storage_id || null,
      user_id: input.user_id || 'anonymous',
      image_url: imageUrl,
      image_base64: imageBase64,
      image_mime: input.image_mime || 'image/jpeg',
      needs_image_fetch: imageUrl && !imageBase64 ? true : false,
      callback_url: callbackUrl,
      location: {
        latitude: lat,
        longitude: lon,
        address: addr,
      },
      description: input.user_description || input.description || '',
      timestamp: input.timestamp || input.created_at || new Date().toISOString(),
      validated_at: new Date().toISOString(),
    },
  });
}

return results;

const items = $input.all();
const originalData = $('Validate Input').first().json;
const results = [];

for (const item of items) {
  let imageBase64 = originalData.image_base64;
  let imageMime = originalData.image_mime || 'image/jpeg';

  if (item.binary && item.binary.data) {
    const binaryBuffer = await this.helpers.getBinaryDataBuffer(item.index ?? 0, 'data');
    imageBase64 = binaryBuffer.toString('base64');
    imageMime = item.binary.data.mimeType || 'image/jpeg';
  }

  results.push({
    json: {
      ...originalData,
      image_base64: imageBase64,
      image_mime: imageMime,
      needs_image_fetch: false
    }
  });
}

return results;

const items = $input.all();
const results = [];

const systemPrompt = `You are an environmental issue analyzer for a city reporting app. Analyze the image and provide a structured assessment.

Your Task: Identify the problem, classify severity, suggest who should handle it.

Severity Levels:
- EASY: Small litter, minor graffiti, overgrown grass, small broken items, faded signs
- MEDIUM: Large trash piles, broken public furniture, potholes under 20cm, damaged fencing, blocked drains, small dead animals, vandalism
- HIGH: Fallen trees blocking roads, large potholes (safety hazard), exposed wires, gas leaks, flooding, structural damage, hazardous waste, immediate danger

Categories: trash, road_damage, vegetation, vandalism, utilities, infrastructure, safety_hazard, pollution, animal, other

Authority Types: sanitation, roads_department, parks_department, utilities_electric, utilities_water, utilities_gas, police, emergency_services, animal_control, environmental

Respond in JSON:
{"severity":"EASY|MEDIUM|HIGH","category":"category","problem_detected":true,"description":"description","specific_issue":"type","confidence":0.0-1.0,"authority_type":"authority","safety_concern":false,"estimated_effort":"effort","recommended_action":"action","notes":"notes"}

If no problem: {"severity":null,"problem_detected":false,"description":"No issue detected","notes":"what image shows"}`;

for (const item of items) {
  const data = item.json;

  results.push({
    json: {
      ...data,
      ai_request_body: {
        contents: [{
          role: 'user',
          parts: [
            { text: systemPrompt + '\n\nAnalyze this image and describe what you see. Identify any environmental issues.' + (data.location.latitude && data.location.longitude && !(data.location.latitude === 0 && data.location.longitude === 0) ? ' Coordinates: ' + data.location.latitude + ', ' + data.location.longitude + '.' : '') + (data.location.address !== 'Unknown' ? ' Location: ' + data.location.address + '.' : '') + (data.description ? ' Additional context: ' + data.description : '') },
            { inline_data: { mime_type: data.image_mime || 'image/jpeg', data: data.image_base64 } }
          ]
        }],
        generationConfig: {
          responseMimeType: 'application/json',
          maxOutputTokens: 900,
          temperature: 0.2
        }
      }
    }
  });
}

return results;

