function parseAiJson(raw) {
  if (typeof raw !== 'string') return null;
  const t = raw.trim();
  if (!t) return null;

  // 1) direct JSON
  try { return JSON.parse(t); } catch (e) {}

  // 2) markdown fenced JSON
  const fenced = t.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fenced && fenced[1]) {
    try { return JSON.parse(fenced[1].trim()); } catch (e) {}
  }

  // 3) first object-like block
  const firstBrace = t.indexOf('{');
  const lastBrace = t.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    const candidate = t.slice(firstBrace, lastBrace + 1);
    try { return JSON.parse(candidate); } catch (e) {}
  }

  return null;
}

function normalizeSeverity(value) {
  const s = String(value || '').trim().toUpperCase();
  const map = {
    LOW: 'EASY',
    MINOR: 'EASY',
    MODERATE: 'MEDIUM',
    NORMAL: 'MEDIUM',
    SEVERE: 'HIGH',
    CRITICAL: 'HIGH',
    URGENT: 'HIGH'
  };
  return map[s] || s;
}

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const originalData = preparedItems[i]?.json || preparedItems[0]?.json || {};
  const aiResponse = item.json;
  const content = aiResponse.candidates?.[0]?.content?.parts?.[0]?.text
    || aiResponse.choices?.[0]?.message?.content
    || '';

  const parsed = parseAiJson(content);
  let aiResult;

  if (parsed) {
    aiResult = parsed;
  } else {
    aiResult = {
      severity: 'MEDIUM',
      problem_detected: true,
      description: content || 'Unable to parse AI response',
      confidence: 0.4,
      notes: 'Failed to parse structured response'
    };
  }

  const severity = normalizeSeverity(aiResult.severity);
  const validSeverities = ['EASY', 'MEDIUM', 'HIGH'];
  aiResult.severity = validSeverities.includes(severity) ? severity : 'MEDIUM';

  if (aiResult.problem_detected === false && !validSeverities.includes(severity)) {
    aiResult.severity = 'EASY';
  }

  const priorityScores = { EASY: 3, MEDIUM: 6, HIGH: 10 };

  results.push({
    json: {
      ...originalData,
      ai_result: aiResult,
      ai_raw_response: content,
      priority_score: priorityScores[aiResult.severity],
      processed_by_ai: true,
      ai_processed_at: new Date().toISOString()
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json || {};
  const lat = Number(data.location?.latitude);
  const lon = Number(data.location?.longitude);

  let resolvedAddress = data.location?.address || 'Unknown';

  const hasCoords = Number.isFinite(lat) && Number.isFinite(lon) && !(lat === 0 && lon === 0);

  if (hasCoords) {
    try {
      const geocode = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lon}&format=json&addressdetails=1`,
        headers: { 'User-Agent': 'CityReporterApp/1.0' },
        json: true,
        timeout: 10000
      });

      if (geocode?.display_name) {
        resolvedAddress = geocode.display_name;
      }
    } catch (e) {
      // Keep original address if reverse geocoding fails.
    }
  }

  results.push({
    json: {
      ...data,
      location: {
        latitude: data.location?.latitude,
        longitude: data.location?.longitude,
        address: resolvedAddress
      },
      geocoded_at: new Date().toISOString()
    }
  });
}

return results;

