const items = $input.all();
const highData = $('HIGH Handler').first().json;

// Optional: set a static Behörden-E-Mail here to skip the Gemini contact lookup (leave '' for AI search).
const AUTHORITY_EMAIL_OVERRIDE = '';

const results = [];

for (const item of items) {
  const geocode = item.json;
  const address = geocode.display_name || highData.location.address;
  const city = geocode.address?.city || geocode.address?.town || 'Unknown';
  const country = geocode.address?.country || 'Unknown';

  const base = {
    geocode_data: geocode,
    geocode_address: address,
    geocode_city: city
  };

  const trimmedOverride = String(AUTHORITY_EMAIL_OVERRIDE || '').trim();
  if (trimmedOverride) {
    results.push({
      json: {
        ...base,
        skip_ai_authority_search: true,
        authority: {
          authority_name: 'Stadtverwaltung',
          department: 'Allgemeine Anfragen',
          email: trimmedOverride,
          confidence: 1,
          notes: 'Static email set in Prepare Authority Lookup (AUTHORITY_EMAIL_OVERRIDE)'
        }
      }
    });
    continue;
  }

  const prompt = `Find the real contact information for the local government authority responsible for this issue.

Issue type: ${highData.ai_result.category}
Authority needed: ${highData.ai_result.authority_type}
City: ${city}
Full address: ${address}
Country: ${country}

Search for the REAL official email address and department name of the municipal authority in ${city} that handles ${highData.ai_result.category} issues.

For example, if this is in Heilbronn, Germany, look for the Stadtverwaltung Heilbronn department contacts.

Respond in JSON format ONLY:
{
  "authority_name": "Official name of the authority/department",
  "department": "Specific department",
  "email": "real official email address",
  "phone": "phone number if known",
  "website": "official website URL",
  "confidence": 0.0-1.0,
  "notes": "any relevant notes"
}`;

  results.push({
    json: {
      ...base,
      skip_ai_authority_search: false,
      authority_lookup_body: {
        contents: [{
          role: 'user',
          parts: [{ text: 'You are a municipal authority contact finder. Return only valid JSON with real, verifiable government contact information. If you cannot find a specific contact, return the general municipality contact for the city.\n\n' + prompt }]
        }],
        generationConfig: {
          responseMimeType: 'application/json',
          maxOutputTokens: 500,
          temperature: 0.1
        }
      }
    }
  });
}

return results;

const items = $input.all();
const out = [];

for (const item of items) {
  const j = item.json || {};

  if (j.skip_ai_authority_search && j.authority) {
    out.push({ json: j });
    continue;
  }

  const model = $vars.GEMINI_MODEL || 'gemini-2.5-flash';
  const key = $vars.AI_API_KEY;
  if (!key) {
    throw new Error('Missing n8n variable AI_API_KEY for authority lookup');
  }

  const url = 'https://generativelanguage.googleapis.com/v1beta/models/' + model + ':generateContent?key=' + key;

  const response = await this.helpers.httpRequest({
    method: 'POST',
    url,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(j.authority_lookup_body),
    json: true
  });

  out.push({ json: response });
}

return out;

const items = $input.all();
const highItems = $('HIGH Handler').all();
const lookupItems = $('Prepare Authority Lookup').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const itemJson = items[i].json || {};
  const highData = highItems[i]?.json || highItems[0]?.json || {};
  const lookupData = lookupItems[i]?.json || lookupItems[0]?.json || {};

  let authority = itemJson.authority;

  if (!authority) {
    const content = itemJson.candidates?.[0]?.content?.parts?.[0]?.text
      || itemJson.choices?.[0]?.message?.content
      || '';

    try {
      authority = JSON.parse(content);
    } catch (e) {
      authority = {
        authority_name: 'Stadtverwaltung',
        department: 'Allgemeine Anfragen',
        email: 'info@' + String(lookupData.geocode_city || 'stadt').toLowerCase().replace(/\s+/g, '') + '.de',
        confidence: 0.2,
        notes: 'AI authority parsing failed, fallback used'
      };
    }
  }

  const address = lookupData.geocode_address || highData.location?.address || 'Unbekannt';
  const city = lookupData.geocode_city || 'Unbekannt';
  const country = lookupData.geocode_data?.address?.country || 'Deutschland';
  const mapsLink = 'https://maps.google.com/?q=' + highData.location?.latitude + ',' + highData.location?.longitude;
  const desc = String(highData.ai_result?.description || '').replace(/"/g, "'");

  const factsDe = [
    'Meldungs-ID: ' + highData.issue_id,
    'Zeitpunkt: ' + highData.timestamp,
    'Kategorie: ' + (highData.ai_result?.category || 'unbekannt'),
    'Schweregrad (KI): ' + (highData.ai_result?.severity || 'HIGH'),
    'Beschreibung: ' + desc,
    'Sicherheitsrisiko: ' + (highData.ai_result?.safety_concern ? 'ja' : 'nein'),
    'Ort: ' + address + ', ' + city + ', ' + country,
    'Koordinaten: ' + highData.location?.latitude + ', ' + highData.location?.longitude,
    'Karte: ' + mapsLink,
    'Zustaendigkeit (KI-Vorschlag): ' + (highData.ai_result?.authority_type || 'unbekannt'),
    'Behoerde: ' + (authority.authority_name || '') + ' - ' + (authority.department || '') + ' - E-Mail: ' + (authority.email || '')
  ].join('\n');

  const systemPrompt = 'Du bist ein Assistent fuer eine Buerger-Meldestelle (Stadt/Umwelt). Antworte NUR mit gueltigem JSON (kein Markdown, kein Kommentar).';

  const userPrompt = 'Pruefe die folgende HIGH-Prioritaets-Meldung und entscheide, ob eine formelle E-Mail an die oertliche Behoerde sachlich gerechtfertigt und sinnvoll ist (echtes staedtisches oder anliegerrelevantes Problem, kein Spam, kein offensichtlicher Fehlalarm).\n\n' +
    'Wenn NEIN: setze worth_sending auf false, verfasse skip_reason_de (kurz, deutsch) und lasse email_subject_de sowie email_body_html_de als leere Strings.\n\n' +
    'Wenn JA: setze worth_sending auf true und verfasse eine hoefliche, foermliche E-Mail auf Deutsch (Sie-Form) an die genannte Behoerde: kurzer Betreff, strukturierter Fliesstext, verlinkte Karte, sachlich und respektvoll. Verwende einfaches HTML (<p>, <br>, <strong>, <ul><li>).\n\n' +
    'Antwortformat (exakt diese Schluessel, boolescher Wert fuer worth_sending):\n' +
    '{\n  "worth_sending": false,\n  "urgency_summary_de": "",\n  "skip_reason_de": "",\n  "email_subject_de": "",\n  "email_body_html_de": ""\n}\n\n' +
    'Fakten zur Meldung:\n' + factsDe;

  results.push({
    json: {
      issue_id: highData.issue_id,
      timestamp: highData.timestamp,
      user_id: highData.user_id,
      image_url: highData.image_url,
      location: highData.location,
      ai_result: highData.ai_result,
      geocode_address: address,
      geocode_city: city,
      authority,
      mapsLink,
      german_email_ai_body: {
        contents: [{
          role: 'user',
          parts: [{ text: systemPrompt + '\n\n' + userPrompt }]
        }],
        generationConfig: {
          responseMimeType: 'application/json',
          maxOutputTokens: 2048,
          temperature: 0.25
        }
      }
    }
  });
}

return results;

const preparedItems = $('Prepare German Email AI').all();
const geminiItems = $input.all();
const results = [];

for (let i = 0; i < geminiItems.length; i++) {
  const prep = preparedItems[i]?.json || {};
  const gemini = geminiItems[i].json;
  const text = gemini.candidates?.[0]?.content?.parts?.[0]?.text
    || gemini.choices?.[0]?.message?.content
    || '';

  let draft = {};
  try {
    draft = JSON.parse(text);
  } catch (e) {
    draft = {
      worth_sending: true,
      urgency_summary_de: 'KI-Antwort nicht parsebar — Fallback.',
      skip_reason_de: '',
      email_subject_de: 'Meldung ' + prep.issue_id + ' — bitte prüfen',
      email_body_html_de: '<p>Die automatische Formulierung ist fehlgeschlagen. Bitte Daten im System prüfen.</p>'
    };
  }

  const worth = draft.worth_sending === true;
  const authorityEmail = prep.authority?.email || '';
  const city = prep.geocode_city || '';

  if (!worth) {
    const reason = String(draft.skip_reason_de || 'Kein Versand empfohlen.').replace(/</g, '&lt;');
    results.push({
      json: {
        ...prep,
        email_subject: '[Kein Behörden-Versand] ' + prep.issue_id,
        email_html: '<p><strong>KI hat keinen Behördenversand empfohlen.</strong></p><p>' + reason + '</p>',
        authority_email: authorityEmail || null,
        email_status: 'skipped_not_worth_sending',
        ai_email_draft: draft
      }
    });
  } else {
    results.push({
      json: {
        ...prep,
        email_subject: draft.email_subject_de || ('Stadtmeldung ' + prep.issue_id + ' (' + city + ')'),
        email_html: draft.email_body_html_de || '<p>(Kein Inhalt)</p>',
        authority_email: authorityEmail,
        email_status: 'ready_to_send',
        ai_email_draft: draft
      }
    });
  }
}

return results;

const items = $input.all();

